import React from 'react';
import './App.css';
import { Link, useNavigate } from 'react-router-dom'; 

const Modal = ({ isOpen, onClose }) => { 

    const modalOc = document.querySelector('.modal_1 > li:first-child')
    // useNavigate는 컴포넌트 상단에서 호출해야 합니다
    const navigate = useNavigate();  // useNavigate 훅 호출
    if (!isOpen) return null;  // isOpen이 false일 때 모달을 렌더링하지 않음야 함


    function handleClick() {
        // navigate로 페이지 이동
        navigate('/diarypage');
    } 
    return (
        <div className='modal'>
            <ul className='modal_1'>
               <li>
                    잘자요
               </li>
                <li>
                    <Link to='/'>애칭 설정</Link>
                </li>
                <li>
                    <Link to='/'>Diray List</Link>
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
